import java.util.Scanner;
public class SumFiveNumbers {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int sum = 0;

        System.out.println("enter number:");
        for (int i = 0; i < 5; i++) {
            int num = scanner.nextInt();
            sum += num;
        }

        System.out.println("Sum: " + sum);
    }
}
- Imports Scanner correctly <marks>1 mark</marks>
- Uses the for loop to ask 5 times <marks>1 mark</marks>
- Reads integer input correctly using the Scanner class <marks>1 mark</marks>
- Adds to total correctly <marks>1 mark</marks>
